    int strongPasswordChecker(string password) {
        int needLower = password.find_first_not_of("abcdefghijklmnopqrstuvwxyz") == string::npos ? 1 : 0;
        int needUpper = password.find_first_not_of("ABCDEFGHIJKLMNOPQRSTUVWXYZ") == string::npos ? 1 : 0;
        int needDigit = password.find_first_not_of("0123456789") == string::npos ? 1 : 0;
        int needNonRepeat = 0;
        int i = 0;
        while (i < password.length()) {
            if (i > 0 && password[i] == password[i - 1] && password[i] == password[i - 2]) {
                needNonRepeat++;
                i += 3;
            } else {
                i++;
            }
        }
        int res = max(needLower, max(needUpper, needDigit)) + needNonRepeat;
        res = max(res, password.length() - 20);
        res = max(res, 6 - password.length());
        return res;
    }
};```
